// app/(auth)/login/page.tsx
'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import AuthLayout from '@/app/components/authlayout/AuthLayout';
import { authService } from '@/app/services/auth'; // Importe ton service
import { useData } from '@/app/context/DataContext';

export default function LoginPage() {
  const router = useRouter();
  const { refreshData } = useData();

  // États pour stocker les saisies
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setIsLoading(true);

    try {
      // Appel au backend via notre service
      await authService.login(email, password);

      // On rafraîchit les données du contexte
      await refreshData();

      // Si ça marche, on redirige vers le dashboard ou le profil
      router.push('/dashboard');
    } catch (err: any) {
      // Gestion d'erreur (ex: mauvais mot de passe)
      setError(err.message || "Une erreur est survenue");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <AuthLayout
      title="Connexion"
      imageSrc="/images/login.png"
      bottomText="Pas encore de compte ?"
      linkText="Créer un compte"
      linkUrl="/register"
    >
      <form onSubmit={handleSubmit} className="flex flex-col gap-5">
        {error && (
          <div className="bg-red-50 text-red-600 text-sm p-3 rounded-lg border border-red-200">
            {error}
          </div>
        )}
        <div className="flex flex-col gap-1 shrink-0">
          <label htmlFor="email" className="text-xs font-bold text-gray-500 ml-1">Email</label>
          <input
            id="email"
            aria-label='email'
            required
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="w-full h-13 px-4 border border-gray-200 bg-gray-50 rounded-lg outline-none focus:ring-2 focus:ring-[#E85D04] transition-all"
          />
        </div>

        <div className="flex flex-col gap-1 shrink-0">
          <label htmlFor="password" className="text-xs font-bold text-gray-500 ml-1">Mot de passe</label>
          <input
            aria-label='password'
            type="password"
            id="password"
            required
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="w-full h-13 px-4 border border-gray-200 bg-gray-50 rounded-lg outline-none focus:ring-2 focus:ring-[#E85D04] transition-all"
          />
        </div>

        <button className="bg-black shrink-0 h-13 text-white font-bold rounded-lg hover:bg-gray-800 transition-colors mt-2">
          {isLoading ? 'Connexion...' : 'Se connecter'}
        </button>

        <div className="text-center">
          <a href="#" className="text-xs text-orange-500 hover:underline">Mot de passe oublié ?</a>
        </div>
      </form>
    </AuthLayout>
  );
}

// app/(auth)/register/page.tsx
'use client'; // ⚠️ Indispensable pour utiliser useState et useRouter

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import AuthLayout from '@/app/components/authlayout/AuthLayout';
import { authService } from '@/app/services/auth'; // Assure-toi que le chemin est bon

export default function RegisterPage() {
  const router = useRouter();

  // 1. Les états pour stocker ce que l'utilisateur tape
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  // États pour gérer le chargement et les erreurs
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  // 2. La fonction qui se lance quand on clique sur "S'inscrire"
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault(); // Empêche la page de se recharger
    setError(null);
    setIsLoading(true);

    try {
      // On appelle le backend
      // On passe une chaîne vide pour le nom car il est optionnel mais attendu par la signature
      await authService.register("", email, password);

      // Si tout se passe bien, on redirige vers le login 
      // (ou directement vers le dashboard si ton API connecte l'utilisateur auto)
      router.push('/login');
    } catch (err: any) {
      setError(err.message || "Une erreur est survenue lors de l'inscription.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <AuthLayout
      title="Inscription"
      imageSrc="/images/signin.png"
      bottomText="Déjà inscrit ?"
      linkText="Se connecter"
      linkUrl="/login"
    >
      <form onSubmit={handleSubmit} className="flex flex-col gap-5">

        {/* Affichage des erreurs en rouge si besoin */}
        {error && (
          <div className="bg-red-50 text-red-600 text-sm p-3 rounded-lg border border-red-200">
            {error}
          </div>
        )}

        <div className="flex flex-col gap-1 shrink-0">
          <label htmlFor="email" className="text-xs font-bold text-gray-500 ml-1">Email</label>
          <input
            aria-label='email'
            type="email"
            id="email"
            required
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="w-full h-13 px-4 border border-gray-200 bg-white rounded-lg outline-none focus:ring-2 focus:ring-[#E85D04] transition-all"
          />
        </div>

        <div className="flex flex-col gap-1 shrink-0">
          <label htmlFor="password" className="text-xs font-bold text-gray-500 ml-1">Mot de passe</label>
          <input
            aria-label='password'
            type="password"
            id="password"
            required
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            // J'ai uniformisé en rounded-lg pour que ce soit joli comme l'email
            className="w-full h-13 px-4 border border-gray-200 bg-white rounded-lg outline-none focus:ring-2 focus:ring-[#E85D04] transition-all"
          />
          <p className="text-[12px] text-gray-500 ml-1">
            Min. 8 caractères, 1 majuscule, 1 minuscule, 1 chiffre.
          </p>
        </div>

        <button
          disabled={isLoading}
          className="bg-black shrink-0 h-13 text-white font-bold rounded-lg hover:bg-gray-800 transition-colors mx-3 mt-2 disabled:opacity-50"
        >
          {isLoading ? 'Inscription en cours...' : "S'inscrire"}
        </button>
      </form>
    </AuthLayout>
  );
}

import { NextResponse } from 'next/server';
import { Document, VectorStoreIndex, Settings } from "llamaindex";
import { MistralAI, MistralAIEmbedding, MistralAIEmbeddingModelType } from "@llamaindex/mistral";

export async function POST(req: Request) {
    try {
        const { demandeUtilisateur, tachesExistantes } = await req.json();

        if (!demandeUtilisateur) {
            return NextResponse.json(
                { message: "La demande utilisateur est requise" },
                { status: 400 }
            );
        }

        const apiKey = process.env.MISTRAL_API_KEY;
        if (!apiKey) {
            return NextResponse.json(
                { message: "Clé API Mistral manquante" },
                { status: 500 }
            );
        }

        // Configuration de LlamaIndex pour utiliser Mistral (LLM et Embeddings)
        Settings.llm = new MistralAI({
            apiKey: apiKey,
            model: "mistral-small-latest",
            additionalKwargs: { response_format: { type: "json_object" } } // Force le JSON
        } as any);

        Settings.embedModel = new MistralAIEmbedding({
            apiKey: apiKey,
            model: MistralAIEmbeddingModelType.MISTRAL_EMBED
        });

        // 1. Créer des Documents à partir des tâches existantes
        // Transformer les tâches en format texte pour l'indexation
        const documents = (tachesExistantes || []).map((t: any) => new Document({
            text: `Titre: ${t.title}, Statut: ${t.status || 'TODO'}, Description: ${t.description || ''}`,
            metadata: { id: t.id, title: t.title }
        }));

        // Si aucun document, on en crée un factice pour permettre la création de l'index
        if (documents.length === 0) {
            documents.push(new Document({ text: "Aucune tâche existante." }));
        }

        // 2. Créer le VectorStoreIndex (RAG)
        // Cela indexe les documents en mémoire pour la récupération
        const index = await VectorStoreIndex.fromDocuments(documents);

        // 3. Créer le moteur de recherche (Query Engine)
        // On récupère plus de contexte (20 tâches) pour éviter les doublons
        const queryEngine = index.asQueryEngine({ similarityTopK: 20 });

        // 4. Interroger le moteur
        const promptSystem = `
      Tu es un expert en gestion de projet.
      Génère une liste de NOUVELLES tâches pour répondre à : "${demandeUtilisateur}".
      Ta réponse doit compléter le projet sans créer de doublons avec les tâches contextuelles.
      Réponds UNIQUEMENT avec un tableau JSON d'objets.
      Chaque objet doit avoir : "name" (titre) et "description".
      Le format doit être un tableau JSON valide, sans texte avant ni après.
      Exemple : [{"name": "...", "description": "..."}]
    `;

        const response = await queryEngine.query({
            query: promptSystem,
        });

        const content = response.toString();

        // Analyse du JSON
        let tasks;
        try {
            // Nettoyer les blocs de code si du markdown standard est retourné
            const cleanContent = content.replace(/```json/g, '').replace(/```/g, '').trim();
            tasks = JSON.parse(cleanContent);

            if (tasks.tasks && Array.isArray(tasks.tasks)) {
                tasks = tasks.tasks;
            }
        } catch (e) {
            console.error("Erreur parsing JSON IA:", e);
            // Fallback : Retourner le texte brut si l'analyse échoue (debug)
            console.log("Raw Content:", content);
            return NextResponse.json({ message: "Format de réponse invalide de l'IA" }, { status: 500 });
        }

        return NextResponse.json(tasks);

    } catch (error: any) {
        console.error("Erreur API Chat (LlamaIndex):", error);
        return NextResponse.json(
            { message: error.message || "Erreur interne" },
            { status: 500 }
        );
    }
}

import { NextResponse } from 'next/server';
import { cookies } from 'next/headers';

const API_URL = "http://localhost:8000"; // Backend Django (Must be absolute for server fetch)

export async function GET() {
    const cookieStore = await cookies();
    const token = cookieStore.get('token')?.value;

    if (!token) {
        return NextResponse.json({ message: 'Unauthorized' }, { status: 401 });
    }

    const headers = {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
    };

    try {
        // Appels parallèles
        const [userRes, tasksRes, projectsRes] = await Promise.all([
            fetch(`${API_URL}/auth/profile`, { headers }).catch(e => { console.error("User fetch error:", e); return null; }),
            fetch(`${API_URL}/dashboard/assigned-tasks`, { headers }).catch(e => { console.error("Tasks fetch error:", e); return null; }),
            fetch(`${API_URL}/projects`, { headers }).catch(e => { console.error("Projects fetch error:", e); return null; })
        ]);

        const user = userRes?.ok ? (await userRes.json()).data?.user : null;

        // Traitement des tâches
        let tasks = [];
        if (tasksRes?.ok) {
            const taskJson = await tasksRes.json();
            const rawTasks = taskJson.data?.tasks || taskJson.data || [];

            tasks = rawTasks.map((t: any) => {
                const normalizedCall = { ...t };

                // Normalisation des assignations
                if (!normalizedCall.assignees || normalizedCall.assignees.length === 0) {
                    const candidate = t.assignee || t.assignedTo || t.assigned_to;
                    if (candidate) {
                        normalizedCall.assignees = Array.isArray(candidate) ? candidate : [candidate];
                    } else {
                        normalizedCall.assignees = [];
                    }
                }
                return normalizedCall;
            });
        }

        // Enrichissement des données projets
        let projects = [];
        if (projectsRes?.ok) {
            const projectJson = await projectsRes.json();
            const rawProjects = projectJson.data?.projects || projectJson.data || [];

            projects = await Promise.all(rawProjects.map(async (p: any) => {
                let doneCount = 0;
                let totalCount = p._count?.tasks || 0;

                try {
                    // Récupération des détails pour calcul de progression
                    const detailRes = await fetch(`${API_URL}/projects/${p.id}`, { headers });
                    if (detailRes.ok) {
                        const detailJson = await detailRes.json();
                        const detailData = detailJson.data?.project || detailJson.data;

                        if (detailData && detailData.tasks) {
                            doneCount = detailData.tasks.filter((t: any) => t.status === 'DONE').length;
                            totalCount = detailData._count?.tasks || detailData.tasks.length || totalCount;
                        }
                    }
                } catch (err) {
                    console.warn(`Failed to fetch details for project ${p.id}`, err);
                }

                // Utilitaire d'initiales
                const getInitials = (name: string) => {
                    const parts = name.trim().split(' ');
                    if (parts.length === 1) return parts[0].substring(0, 2).toUpperCase();
                    return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
                };

                // Préparation des avatars
                const ownerAvatar = { initials: getInitials(p.owner?.name || "Inconnu") };
                const memberAvatars = p.members?.map((m: any) => ({
                    initials: getInitials(m.user?.name || "Inconnu")
                })) || [];
                const allAvatars = [ownerAvatar, ...memberAvatars];

                // Composition de l'équipe
                const team = [
                    {
                        id: p.owner?.id || "owner",
                        email: p.owner?.email,
                        name: p.owner?.name || "Propriétaire",
                        initials: ownerAvatar.initials,
                        role: "Propriétaire"
                    },
                    ...(p.members?.map((m: any) => ({
                        id: m.user?.id || "unknown",
                        email: m.user?.email,
                        name: m.user?.name || "Membre",
                        initials: getInitials(m.user?.name || "Inconnu"),
                        role: m.role || "Membre"
                    })) || [])
                ];

                return {
                    id: p.id,
                    title: p.name || "Projet Sans Nom",
                    description: p.description || "",

                    // Calculs statistiques
                    progressPercent: totalCount > 0 ? Math.round((doneCount / totalCount) * 100) : 0,
                    doneTasks: doneCount,
                    totalTasks: totalCount,

                    teamCount: allAvatars.length,
                    ownerLabel: "Propriétaire",
                    ownerAvatars: allAvatars,
                    team: team
                };
            }));
        } else {
            console.warn("Impossible de récupérer les projets via /projects");
        }

        return NextResponse.json({
            success: true,
            data: {
                user,
                tasks,
                projects
            }
        });

    } catch (error) {
        console.error('Unified API Error:', error);
        return NextResponse.json({ message: 'Internal Server Error' }, { status: 500 });
    }
}

'use client';

import Image from "next/image";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { useData } from "@/app/context/DataContext";
import { useState } from "react";



type ModalType = "PROFIL" | null;

export default function Header() {
    const pathname = usePathname();
    const { user } = useData();


    const isActive = (path: string) => pathname === path;

    const getLinkClass = (path: string) => {
        const active = isActive(path);
        const base = "flex items-center justify-center gap-0 md:gap-3 rounded-[10px] transition-all font-semibold text-sm";

        if (active) {
            return `${base} bg-black text-white shadow-md w-[50px] h-[50px] md:w-[248px] md:h-[78px]`;
        }
        return `${base} text-[#E85D04] hover:bg-orange-50 w-[50px] h-[50px] md:w-[248px] md:h-[78px]`;
    };

    const getIconClass = (path: string) => {
        return isActive(path) ? "brightness-0 invert" : "";
    };

    // Calcul des initiales
    const getInitials = () => {
        if (!user || !user.name) return "AD";
        return user.name
            .split(" ")
            .map((n: string) => n[0])
            .join("")
            .toUpperCase()
            .slice(0, 2);
    };

    return (
        <header>
            <div className="flex justify-between items-center h-20 md:h-24 px-4 md:px-10 bg-white">
                <div>
                    <Image src="/images/logo.svg" alt="Logo" width={150} height={150} className="w-[110px] md:w-[150px]" />
                </div>
                <div className="flex gap-2 md:gap-4">
                    <Link href="/dashboard" className={getLinkClass('/dashboard')}>
                        <Image
                            src="/images/Group-3.svg"
                            alt="Dashboard"
                            width={20}
                            height={20}
                            className={getIconClass('/dashboard')}
                        />
                        <span className="hidden md:block">Tableau de bord</span>
                    </Link>
                    <Link href="/projet" className={getLinkClass('/projet')}>
                        <Image
                            src="/images/Union.svg"
                            alt="Projets"
                            width={20}
                            height={20}
                            className={getIconClass('/projet')}
                        />
                        <span className="hidden md:block">Projets</span>
                    </Link>
                </div>
                <div>
                    <Link href="/compte/moncompte">
                        {/* Avatar dynamique */}
                        <button
                            className={`w-[40px] h-[40px] md:w-[50px] md:h-[50px] rounded-full flex items-center justify-center text-[12px] md:text-[14px] font-normal transition-all border cursor-pointer focus:outline-none focus:ring-2 focus:ring-orange-200 ${pathname.startsWith('/compte')
                                ? "bg-[#E85D04] text-white "
                                : "bg-orange-100 text-gray-700 border-orange-50 hover:bg-orange-100"
                                }`}
                            title={user?.name || "Chargement..."}
                        >
                            {getInitials()}
                        </button>
                    </Link>

                </div>
            </div>

        </header>
    );
}

'use client'
import { useState } from 'react';
import { Trash2, Pencil, Plus, Loader2 } from 'lucide-react';
import { useData } from '@/app/context/DataContext';
import ModalModifyTask from '../modal/ModalModifTache';
import { AssignedTask } from '@/app/services/task';

interface Props {
    projectId: string;
    members?: { id: string; name: string }[];
    onClose?: () => void;
    onSuccess?: () => void;
    existingTasks?: AssignedTask[];
}

export default function IATaskManager({ projectId, onClose, members = [], onSuccess, existingTasks = [] }: Props) {
    const { createTask } = useData();
    const [step, setStep] = useState(1);
    const [prompt, setPrompt] = useState("");
    const [tasks, setTasks] = useState<{
        name: string;
        description: string;
        status?: string;
        dueDate?: string;
        assignees?: string[]
    }[]>([]);

    const [loading, setLoading] = useState(false);
    const [saving, setSaving] = useState(false);
    const [editingIndex, setEditingIndex] = useState<number | null>(null);

    const handleGenerate = async () => {
        if (!prompt.trim()) return;
        setLoading(true);
        try {
            const res = await fetch('/api/chat', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    demandeUtilisateur: prompt,
                    tachesExistantes: existingTasks.map(t => ({ title: t.title, status: t.status }))
                }),
            });

            if (!res.ok) throw new Error("Erreur lors de la génération");

            const data = await res.json();

            // Sécurisation du format de réponse
            const taskList = Array.isArray(data) ? data : (data.tasks || []);

            setTasks(taskList);
            setStep(2);
        } catch (err) {
            console.error(err);
            alert("Une erreur est survenue lors de la génération des tâches.");
        } finally {
            setLoading(false);
        }
    };

    const handleSaveAll = async () => {
        if (tasks.length === 0) return;
        setSaving(true);
        try {
            // On crée les tâches une par une
            for (const task of tasks) {
                await createTask(projectId, {
                    title: task.name,
                    description: task.description,
                    status: (task.status as any) || "TODO",
                    priority: "MEDIUM",
                    dueDate: task.dueDate,
                    assignees: task.assignees || []
                });
            }
            // Tout est bon, on ferme
            if (onSuccess) onSuccess();
            if (onClose) onClose();
        } catch (error) {
            console.error("Erreur sauvegarde IA:", error);
            alert("Erreur lors de la création des tâches.");
        } finally {
            setSaving(false);
        }
    };

    const handleDeleteGeneratedTask = (index: number) => {
        const newTasks = [...tasks];
        newTasks.splice(index, 1);
        setTasks(newTasks);
        if (editingIndex === index) setEditingIndex(null);
        if (newTasks.length === 0) setStep(1);
    };

    const handleUpdateTask = (index: number, updatedData: any) => {
        const newTasks = [...tasks];
        // ModalModifyTask returns { title, description, dueDate, assignees, status }
        // We map it back to our local format
        newTasks[index] = {
            ...newTasks[index],
            name: updatedData.title,
            description: updatedData.description,
            dueDate: updatedData.dueDate,
            assignees: updatedData.assignees,
            status: updatedData.status
        };
        setTasks(newTasks);
        setEditingIndex(null);
    };

    return (
        <div className="flex flex-col h-[600px] w-full md:w-[600px] px-2 relative font-sans">
            {/* TITRE DYNAMIQUE */}
            <div className={`flex items-center gap-3 text-2xl font-semibold text-gray-900 mb-8 flex-shrink-0 ${editingIndex !== null ? 'opacity-50 pointer-events-none' : ''}`}>
                <svg xmlns="http://www.w3.org/2000/svg" width="19" height="19" viewBox="0 0 19 19" fill="none">
                    <path d="M8.24333 0.574802C8.60336 -0.19163 9.69352 -0.19163 10.0535 0.574802L12.351 5.46554C12.4501 5.67658 12.6199 5.84634 12.8309 5.94548L17.7216 8.2429C18.4881 8.60293 18.4881 9.69309 17.7216 10.0531L12.8309 12.3505C12.6199 12.4497 12.4501 12.6194 12.351 12.8305L10.0535 17.7212C9.69352 18.4876 8.60336 18.4876 8.24333 17.7212L5.9459 12.8305C5.84677 12.6194 5.677 12.4497 5.46597 12.3505L0.575229 10.0531C-0.191203 9.69309 -0.191203 8.60293 0.575229 8.2429L5.46597 5.94547C5.677 5.84634 5.84677 5.67658 5.9459 5.46554L8.24333 0.574802Z" fill="#FF8B42" />
                </svg>
                {step === 1 ? "Créer une tâche" : "Vos tâches..."}
            </div>

            {/* CONTENU PRINCIPAL */}
            <div className="flex-1 overflow-y-auto custom-scrollbar pb-24">
                {step === 1 && (
                    <div className="flex flex-col items-center justify-center h-full text-center text-gray-400 space-y-4 opacity-40">
                        {/* Empty state visual */}
                    </div>
                )}

                {step === 2 && (
                    <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
                        {tasks.map((task, index) => {
                            if (editingIndex === index) {
                                return (
                                    <div key={index} className="border border-orange-200 rounded-xl w-[583px] p-4 bg-orange-50/10 shadow-md">
                                        <h4 className="font-bold text-orange-600 text-sm mb-2">Modification de la tâche</h4>
                                        <ModalModifyTask
                                            members={members}
                                            initialTitle={task.name}
                                            initialDescription={task.description}
                                            initialDueDate={task.dueDate || ""}
                                            initialStatus={task.status || "TODO"}
                                            initialAssignees={task.assignees || []}
                                            onSave={(data) => handleUpdateTask(index, data)}
                                            onClose={() => setEditingIndex(null)}
                                            // Override width to fit container
                                            className="w-full !pt-0"
                                        />
                                    </div>
                                );
                            }


                            return (
                                <div key={index} className="border border-gray-100 rounded-xl p-6 shadow-[0_2px_8px_rgba(0,0,0,0.04)] bg-white hover:shadow-md hover:border-gray-200 transition-all group relative">
                                    <h4 className="font-bold text-gray-900 text-[17px] mb-1.5 pr-8">{task.name}</h4>
                                    <p className="text-gray-500 text-[14px] mb-5 leading-relaxed font-normal">{task.description}</p>

                                    {/* Badges d'infos si présents */}
                                    {(task.assignees?.length || task.dueDate) ? (
                                        <div className="flex gap-2 mb-4">
                                            {task.dueDate && (
                                                <span className="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded">
                                                    📅 {new Date(task.dueDate).toLocaleDateString()}
                                                </span>
                                            )}
                                            {task.assignees && task.assignees.length > 0 && (
                                                <span className="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded">
                                                    👤 {task.assignees.length} assigné(s)
                                                </span>
                                            )}
                                        </div>
                                    ) : null}

                                    <div className="flex items-center gap-3 text-[12px] font-medium text-gray-500 border-t border-gray-100 pt-4">
                                        <button
                                            onClick={() => handleDeleteGeneratedTask(index)}
                                            className="flex items-center gap-1.5 hover:text-red-500 transition-colors group"
                                        >
                                            <Trash2 size={14} className="text-gray-400 group-hover:text-red-500" /> Supprimer
                                        </button>
                                        <span className="text-gray-200 text-lg font-light">|</span>
                                        <button
                                            onClick={() => setEditingIndex(index)}
                                            className="flex items-center gap-1.5 hover:text-gray-800 transition-colors group"
                                        >
                                            <Pencil size={14} className="text-gray-400 group-hover:text-gray-800" /> Modifier
                                        </button>
                                    </div>
                                </div>
                            );
                        })}

                        {/* Hide main buttons if editing? No, allow cancelling edit by clicking elsewhere logic handled by local onClose */}
                        {editingIndex === null && (
                            <div className="flex justify-center pt-6 pb-4">
                                <button
                                    onClick={handleSaveAll}
                                    disabled={saving}
                                    className="bg-[#1A1A1A] hover:bg-black text-white px-8 py-3.5 rounded-xl font-medium text-[15px] flex items-center justify-center gap-2 transition-all shadow-lg active:scale-95 disabled:opacity-70 disabled:cursor-not-allowed"
                                >
                                    {saving ? (
                                        <>
                                            <Loader2 className="animate-spin" size={18} /> Création...
                                        </>
                                    ) : (
                                        <>
                                            <Plus size={18} strokeWidth={2.5} /> Ajouter les tâches
                                        </>
                                    )}
                                </button>
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* BARRE DE SAISIE (Sticky Bottom) */}
            {editingIndex === null && (
                <div className="absolute bottom-0 left-0 right-0 bg-white pt-4 pb-2 z-20 px-2">
                    <div className="relative">
                        <input
                            value={prompt}
                            onChange={(e) => setPrompt(e.target.value)}
                            placeholder="Décrivez les tâches que vous souhaitez ajouter..."
                            className="w-full bg-[#F9FAFB] hover:bg-gray-50 focus:bg-white border border-transparent focus:border-gray-100 text-gray-800 placeholder-gray-400 text-[14px] py-4 pl-6 pr-16 rounded-[24px] outline-none transition-all"
                            onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
                            autoFocus={step === 1}
                        />
