import React, { useState, useMemo } from 'react';
import { useData } from '@/app/context/DataContext';
import { ChevronDown } from 'lucide-react';

interface ModalCreerProjetProps {
    onClose?: () => void;
}

export default function ModalCreerProjet({ onClose }: ModalCreerProjetProps) {
    const { projects, createProject, user } = useData();
    const [title, setTitle] = useState("");
    const [description, setDescription] = useState("");
    const [selectedMemberIds, setSelectedMemberIds] = useState<string[]>([]);
    const [isSubmitting, setIsSubmitting] = useState(false);

    // Récupération des utilisateurs uniques
    const availableMembers = useMemo(() => {
        const unique = new Map();
        projects.forEach(p => {
            p.team.forEach(m => {
                // Vérification de l'email
                if (m.id && m.name && !unique.has(m.id) && m.id !== 'unknown' && m.id !== 'owner') {
                    unique.set(m.id, { id: m.id, name: m.name, email: m.email });
                }
            });
        });
        return Array.from(unique.values()) as { id: string; name: string; email?: string }[];
    }, [projects]);

    const handleSubmit = async () => {
        if (!title || !description) return;

        // Préparation des contributeurs
        const contributors = selectedMemberIds
            .map(id => availableMembers.find(m => m.id === id)?.email)
            .filter((email): email is string => !!email);



        setIsSubmitting(true);
        try {
            await createProject({
                name: title,
                description,
                contributors
            });
            if (onClose) onClose();
        } catch (e) {
            console.error(e);
            alert("Erreur lors de la création du projet");
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div className="flex flex-col w-full md:w-149.5 gap-6 pt-2">

            {/* Titre Input */}
            <div className="space-y-2">
                <label htmlFor="projet-title" className="text-sm font-medium text-gray-900">Titre*</label>
                <input
                    id="projet-title"
                    type="text"
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    placeholder="Titre du projet"
                    className="w-full h-10 px-3 rounded-md border border-gray-200 text-sm text-gray-600 focus:outline-none focus:ring-2 focus:ring-orange-100 placeholder:text-gray-300"
                />
            </div>

            {/* Description Input */}
            <div className="space-y-2">
                <label htmlFor="projet-description" className="text-sm font-medium text-gray-900">Description*</label>
                <input
                    id="projet-description"
                    type="text"
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Description du projet"
                    className="w-full h-10 px-3 rounded-md border border-gray-200 text-sm text-gray-600 focus:outline-none focus:ring-2 focus:ring-orange-100 placeholder:text-gray-300"
                />
            </div>

            {/* Contributeurs */}
            <div className="space-y-2">
                <label htmlFor="projet-contributors" className="text-sm font-medium text-gray-900">Contributeurs</label>

                {/* Tags */}
                <div className="flex flex-wrap gap-2 mb-2 empty:hidden">
                    {selectedMemberIds.map(id => {
                        const member = availableMembers.find(m => m.id === id);
                        if (!member) return null;
                        return (
                            <span
                                key={id}
                                role="button"
                                tabIndex={0}
                                onClick={() => setSelectedMemberIds(prev => prev.filter(mid => mid !== id))}
                                onKeyDown={(e) => {
                                    if (e.key === 'Enter' || e.key === ' ') {
                                        e.preventDefault();
                                        setSelectedMemberIds(prev => prev.filter(mid => mid !== id));
                                    }
                                }}
                                className="inline-flex items-center gap-1 px-3 py-1 rounded-full bg-orange-100 text-orange-700 text-sm font-medium cursor-pointer hover:bg-orange-200 transition-colors focus:outline-none focus:ring-2 focus:ring-orange-300"
                            >
                                {member.name}
                                <span className="text-orange-900 font-bold ml-1">×</span>
                            </span>
                        );
                    })}
                </div>

                <div className="relative">
                    <select
                        id="projet-contributors"
                        aria-label="Choisir un ou plusieurs collaborateurs"
                        className="w-full h-10 px-3 rounded-md border border-gray-200 text-sm text-gray-500 cursor-pointer focus:outline-none focus:ring-2 focus:ring-orange-100 bg-white appearance-none"
                        value=""
                        onChange={(e) => {
                            const val = e.target.value;
                            if (val && !selectedMemberIds.includes(val)) {
                                setSelectedMemberIds(prev => [...prev, val]);
                            }
                        }}
                    >
                        <option value="">Choisir un ou plusieurs collaborateurs</option>
                        {availableMembers
                            .filter(m => !selectedMemberIds.includes(m.id))
                            .map((member) => (
                                <option key={member.id} value={member.id}>
                                    {member.name}
                                </option>
                            ))}
                    </select>
                    <ChevronDown className="absolute right-3 top-2.5 text-gray-400 pointer-events-none" size={18} />
                </div>
            </div>

            {/* Bouton Ajouter */}
            <div className="pt-8">
                <button
                    onClick={handleSubmit}
                    disabled={!title || !description || isSubmitting}
                    className={`px-6 py-3 rounded-md text-sm font-semibold transition-colors ${title && description && !isSubmitting
                        ? "bg-gray-200 text-gray-900 hover:bg-gray-300"
                        : "bg-gray-200 text-gray-400 cursor-not-allowed"
                        }`}
                >
                    {isSubmitting ? "Ajout..." : "Ajouter un projet"}
                </button>
            </div>
        </div>
    );
}

import React, { useState } from 'react';
import { Calendar } from 'lucide-react';

interface ModalModifyTaskProps {
    initialTitle: string;
    initialDescription: string;
    initialDueDate: string;
    initialStatus: string;
    initialAssignees: string[]; // List of IDs
    members: { id: string; name: string }[];
    onSave: (data: any) => void;
    onClose: () => void;
    initialAssigneesCount?: number; // kept for compatibility if needed, but unused
    className?: string;
}

export default function ModalModifyTask({
    initialTitle,
    initialDescription,
    initialDueDate,
    initialStatus = "TODO",
    initialAssignees = [],
    members = [],
    onSave,
    onClose,
    className = ""
}: ModalModifyTaskProps) {
    const [title, setTitle] = useState(initialTitle);
    const [description, setDescription] = useState(initialDescription);
    // Ensure format YYYY-MM-DD for input type="date"
    const formatDateForInput = (dateStr: string) => {
        if (!dateStr || dateStr === "-") return "";
        try {
            // Try to parse if it's ISO or Date
            const d = new Date(dateStr);
            if (!isNaN(d.getTime())) {
                return d.toISOString().split('T')[0];
            }
        } catch { }
        return "";
    };

    const [dueDate, setDueDate] = useState(formatDateForInput(initialDueDate));
    const [status, setStatus] = useState(initialStatus);
    const [assignees, setAssignees] = useState<string[]>(initialAssignees);

    const handleSave = () => {
        onSave({
            title,
            description,
            dueDate, // This will be YYYY-MM-DD string
            assignees, // Array of IDs
            status
        });
        onClose();
    };

    return (
        <div className={`flex flex-col gap-6 pt-4 w-full md:w-[560px] ${className}`}>
            {/* Titre */}
            <div className="space-y-2 ">
                <label className="text-sm font-medium text-gray-900">Titre</label>
                <input
                    type="text"
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    className="w-full h-10 px-3 rounded-md border border-gray-200 text-sm text-gray-600 focus:outline-none focus:ring-2 focus:ring-orange-100"
                />
            </div>

            {/* Description */}
            <div className="space-y-2">
                <label className="text-sm font-medium text-gray-900">Description</label>
                <input
                    type="text"
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    className="w-full h-10 px-3 rounded-md border border-gray-200 text-sm text-gray-600 focus:outline-none focus:ring-2 focus:ring-orange-100"
                />
            </div>

            {/* Échéance */}
            <div className="space-y-2">
                <label className="text-sm font-medium text-gray-900">Échéance</label>
                <div className="relative">
                    <input
                        type="date"
                        value={dueDate}
                        onChange={(e) => setDueDate(e.target.value)}
                        className="w-full h-10 px-3 rounded-md border border-gray-200 text-sm text-gray-600 focus:outline-none focus:ring-2 focus:ring-orange-100"
                    />
                    <Calendar className="absolute right-3 top-2.5 text-gray-400 pointer-events-none" size={18} />
                </div>
            </div>

            {/* Assigné à */}
            <div className="space-y-2">
                <label className="text-sm font-medium text-gray-900">Assigné à :</label>

                {/* Liste des assignés sélectionnés tags */}
                <div className="flex flex-wrap gap-2 mb-2">
                    {assignees.map(id => {
                        const member = members.find(m => m.id === id);
                        if (!member) return null;
                        return (
                            <span
                                key={id}
                                role="button"
                                tabIndex={0}
                                onClick={() => setAssignees(prev => prev.filter(mid => mid !== id))}
                                onKeyDown={(e) => {
                                    if (e.key === 'Enter' || e.key === ' ') {
                                        e.preventDefault();
                                        setAssignees(prev => prev.filter(mid => mid !== id));
                                    }
                                }}
                                className="inline-flex items-center gap-1 px-3 py-1 rounded-full bg-orange-100 text-orange-700 text-sm font-medium cursor-pointer hover:bg-orange-200 transition-colors focus:outline-none focus:ring-2 focus:ring-orange-300"
                            >
                                {member.name}
                                <span className="text-orange-900 font-bold ml-1">×</span>
                            </span>
                        );
                    })}
                </div>

                {/* Sélecteur dropdown */}
                <select
                    className="w-full h-10 px-3 rounded-md border border-gray-200 text-sm text-gray-600 cursor-pointer focus:outline-none focus:ring-2 focus:ring-orange-100 bg-white"
                    value=""
                    onChange={(e) => {
                        const val = e.target.value;
                        if (val && !assignees.includes(val)) {
                            setAssignees(prev => [...prev, val]);
                        }
                    }}
                >
                    <option value="">+ Ajouter un collaborateur</option>
                    {members
                        .filter(m => !assignees.includes(m.id))
                        .map((member, idx) => (
                            <option key={`${member.id}-${idx}`} value={member.id}>
                                {member.name}
                            </option>
                        ))}
                </select>
            </div>

            {/* Statut */}
            <div className="space-y-2">
                <label className="text-sm font-medium text-gray-900">Statut :</label>
                <div className="flex gap-2">
                    <button
                        onClick={() => setStatus("TODO")}
                        className={`px-4 py-1.5 rounded-full text-sm font-medium transition-colors ${status === "TODO" ? "bg-red-100 text-red-600" : "bg-red-50 text-red-400 hover:bg-red-100"}`}
                    >
                        À faire
                    </button>
                    <button
                        onClick={() => setStatus("IN_PROGRESS")}
                        className={`px-4 py-1.5 rounded-full text-sm font-medium transition-colors ${status === "IN_PROGRESS" ? "bg-orange-100 text-orange-600" : "bg-orange-50 text-orange-400 hover:bg-orange-100"}`}
                    >
                        En cours
                    </button>
                    <button
                        onClick={() => setStatus("DONE")}
                        className={`px-4 py-1.5 rounded-full text-sm font-medium transition-colors ${status === "DONE" ? "bg-green-100 text-green-600" : "bg-green-50 text-green-400 hover:bg-green-100"}`}
                    >
                        Terminée
                    </button>
                </div>
            </div>

            {/* Bouton Enregistrer */}
            <div className="pt-4">
                <button
                    onClick={handleSave}
                    className="w-[180px] h-10 bg-gray-200 hover:bg-gray-300 text-gray-500 hover:text-gray-700 rounded-md text-sm font-medium transition-colors"
                >
                    Enregistrer
                </button>
            </div>
        </div>
    );
}

import React, { useState, useEffect, useRef } from 'react';
import { MoreHorizontal, Calendar, ChevronUp, Trash2, Pencil } from 'lucide-react';
import Comment from '../comment/Comment';
import { taskService } from '@/app/services/task';
import { useData } from '@/app/context/DataContext';
import Modal from '../modal/Modal';
import ModalModifTache from '../modal/ModalModifTache';

interface Assignee {
    name: string;
    initials: string;
}

interface TacheListeCardProps {
    id: string; // ID required for API calls
    projectId: string; // Project ID required for API calls
    title: string;
    status?: string; // "À faire", "En cours", etc.
    description: string;
    dueDate?: string;
    assignees?: Assignee[];
    commentCount?: number;
    priority?: string;
    comments?: {
        id: string;
        content: string;
        author: { name: string };
        createdAt: string;
    }[];
    members?: { id: string; name: string }[];
    isoDueDate?: string;
    onUpdate?: () => void;
}

const mapStatus = (status: string): "À faire" | "En cours" | "Terminé" => {
    switch (status) {
        case "TODO": return "À faire";
        case "IN_PROGRESS": return "En cours";
        case "DONE": return "Terminé";
        default: return "À faire";
    }
};

const getStatusColor = (status: string): string => {
    switch (status) {
        case "TODO": return "bg-red-50 text-red-500";
        case "IN_PROGRESS": return "bg-orange-50 text-orange-600";
        case "DONE": return "bg-green-50 text-green-600";
        default: return "bg-gray-50 text-gray-500";
    }
};

export default function TacheListeCard({
    id,
    projectId,
    title = "Authentification JWT",
    status = "À faire",
    description = "Implémenter le système d'authentification avec tokens JWT",
    dueDate = "9 mars",
    assignees = [
        { name: "Bertrand Dupont", initials: "BD" },
        { name: "Anne Dupont", initials: "AD" }
    ],
    commentCount = 1,
    comments = [], // Prop for actual comments data
    members = [],
    isoDueDate,
    onUpdate

}: TacheListeCardProps) {
    const [isCommentsOpen, setIsCommentsOpen] = useState(false);
    const [newComment, setNewComment] = useState("");
    const [submitting, setSubmitting] = useState(false);
    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [isModalOpen, setIsModalOpen] = useState(false);
    // On garde l'état d'ouverture du menu pour gérer la vue "confirmation" dedans
    const [menuMode, setMenuMode] = useState<'default' | 'confirm_delete'>('default');
    const menuRef = useRef<HTMLDivElement>(null);

    // État local pour les commentaires (affichage immédiat)
    const [localComments, setLocalComments] = useState(comments || []);

    const { refreshData, user, deleteTask } = useData();

    // Gestion du clic à l'extérieur pour fermer le menu
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
                setIsMenuOpen(false);
                setMenuMode('default'); // On reset si on ferme
            }
        };

        if (isMenuOpen) {
            document.addEventListener("mousedown", handleClickOutside);
        }
        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    }, [isMenuOpen]);

    // Synchro si les props changent (ex: refresh global terminé)
    useEffect(() => {
        if (comments) {
            setLocalComments(comments);
        }
    }, [comments]);

    const getUserInitials = (name: string) => {
        if (!name) return "";
        const parts = name.trim().split(' ');
        if (parts.length === 1) return parts[0].substring(0, 2).toUpperCase();
        return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
    };

    const userInitials = user?.name ? getUserInitials(user.name) : "MOI";

    const handleDeleteTask = async () => {
        try {
            await deleteTask(projectId, id);
            setIsMenuOpen(false);
            if (onUpdate) onUpdate();
        } catch (error) {
            console.error("Erreur suppression:", error);
            alert("Impossible de supprimer la tâche.");
        }
    };

    const handleUpdateTask = async (updatedData: any) => {
        try {
            const payload = {
                title: updatedData.title,
                description: updatedData.description,
                status: updatedData.status,
                // Ensure date is valid before conversion
                dueDate: updatedData.dueDate ? new Date(updatedData.dueDate).toISOString() : null,
                assigneeIds: updatedData.assignees || []
            };

            await taskService.updateTask(projectId, id, payload);

            setIsModalOpen(false);
            // Refresh global data to update UI
            refreshData();
            if (onUpdate) onUpdate();
        } catch (error: any) {
            console.error("Erreur mise à jour:", error);
            alert(`Erreur lors de la mise à jour de la tâche : ${error.message || "Erreur inconnue"}`);
        }
    };

    const handleAddComment = async () => {
        if (!newComment.trim()) return;

        setSubmitting(true);
        try {
            await taskService.addComment(projectId, id, newComment);

            // Optimistic update : Ajout immédiat à la liste locale
            const addedComment = {
                id: `temp-${Date.now()}`,
                content: newComment,
                author: { name: user?.name || "Moi" },
                createdAt: new Date().toISOString()
            };

            setLocalComments(prev => [...prev, addedComment]);
            setNewComment("");

            // Le refresh global se fera en fond
            // refreshData();
        } catch (error) {
            console.error(error);
            alert("Erreur lors de l'ajout du commentaire");
        } finally {
            setSubmitting(false);
        }
    };

    return (
        <div
            role="article"
            tabIndex={0}
            onKeyDown={(e) => {
                if (e.key === 'Enter' && e.target === e.currentTarget) {
                    setIsModalOpen(true);
                }
            }}
            className="w-full bg-white rounded-xl border border-gray-200 p-6 shadow-sm hover:shadow-md transition-shadow focus:outline-none focus:ring-2 focus:ring-orange-200"
        >
            {/* Header: Title + Badge + Menu */}
            <div className="flex justify-between items-start mb-2">
                <div className="flex items-center gap-3">
                    <h3 className="text-base font-bold text-gray-900">{title}</h3>
                    <span className={`text-[11px] font-medium px-2.5 py-0.5 rounded-full ${getStatusColor(status)}`}>
                        {mapStatus(status)}
                    </span>
                </div>
                <div className="relative" ref={menuRef}>
                    <button onClick={() => {
                        setIsMenuOpen(!isMenuOpen);
                        setMenuMode('default');
                    }} className="h-8 w-8 flex items-center justify-center rounded-lg border border-gray-200 text-gray-400 hover:bg-gray-50 bg-white">
                        <MoreHorizontal size={16} />
                    </button>

                    {isMenuOpen && (
                        <div className="absolute right-0 top-10 w-[400px] px-10 py-8 bg-white border border-gray-200 rounded-lg shadow-lg z-50 sm:w-[600px]">
                            {menuMode === 'default' ? (
                                <div className="flex flex-col ">
                                    <h3 className="text-lg font-semibold text-gray-900 mb-1">{title}</h3>
                                    <p className="text-sm text-gray-500 mb-8">{description}</p>
                                    <div className="flex items-center gap-3 text-sm font-medium">
                                        <button
                                            onClick={() => setMenuMode('confirm_delete')}
                                            className="flex items-center gap-2 text-gray-500 hover:text-red-500 transition-colors"
                                        >
