                    initialStatus={status === "En cours" ? "IN_PROGRESS" : status === "Terminé" ? "DONE" : "TODO"}
                    initialAssigneesCount={assignees?.length || 0}
                    // We try to map names back to IDs if ID is missing in assignee object
                    initialAssignees={assignees?.map(a => {
                        // @ts-expect-error
                        if (a.id) return a.id;
                        const found = members.find(m => m.name === a.name);
                        return found ? found.id : null;
                    }).filter(Boolean) as string[] || []}
                    members={members}
                    onSave={handleUpdateTask}
                    onClose={() => setIsModalOpen(false)}
                />
            </Modal>
        </div >
    );
}

"use client";

import React, { useState, useEffect } from 'react';
import { useData } from '@/app/context/DataContext';
import { authService } from '@/app/services/auth';
import { LogOut } from 'lucide-react';

export default function MonCompte() {
    const { user, refreshData } = useData();

    const [lastName, setLastName] = useState("");
    const [firstName, setFirstName] = useState("");
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

    useEffect(() => {
        if (user) {
            // Séparation du nom et prénom
            const parts = (user.name || "").trim().split(' ');
            if (parts.length > 0) {
                setFirstName(parts[0]);
                setLastName(parts.slice(1).join(' ')); // Reste du nom
            }
            setEmail(user.email || "");
        }
    }, [user]);

    const handleSubmit = async () => {
        setIsSubmitting(true);
        setMessage(null);
        try {
            // Reconstruction du nom complet
            const fullName = `${firstName} ${lastName}`.trim();

            const payload: any = {
                name: fullName,
                email: email
            };

            // Envoi du mot de passe uniquement si modifié
            if (password) {
                payload.password = password;
            }

            await authService.updateProfile(payload);
            await refreshData(); // Rafraîchissement des données
            setMessage({ type: 'success', text: "Informations mises à jour avec succès !" });
            setPassword(""); // Réinitialisation du champ mot de passe
        } catch (error: any) {
            console.error("Erreur mise à jour profil:", error);
            setMessage({ type: 'error', text: error.message || "Erreur lors de la mise à jour." });
        } finally {
            setIsSubmitting(false);
        }
    };

    if (!user) return <div className="p-8">Chargement du profil...</div>;

    return (
        <div className="bg-white rounded-2xl border border-gray-200 p-10 max-w-4xl mx-auto">
            <div className="mb-8">
                <h1 className="text-2xl font-bold text-gray-900">Mon compte</h1>
                <p className="text-gray-500 mt-1">{user.name}</p>
            </div>

            <div className="space-y-6">
                {/* Prénom */}
                <div className="space-y-2">
                    <label className="text-sm font-medium text-gray-900">Prénom</label>
                    <input
                        type="text"
                        value={firstName}
                        onChange={(e) => setFirstName(e.target.value)}
                        className="w-full h-12 px-4 rounded-md border border-gray-200 text-sm text-gray-600 focus:outline-none focus:ring-2 focus:ring-orange-100 placeholder:text-gray-300"
                        placeholder="Votre prénom"
                    />
                </div>

                {/* Nom */}
                <div className="space-y-2">
                    <label className="text-sm font-medium text-gray-900">Nom</label>
                    <input
                        type="text"
                        value={lastName}
                        onChange={(e) => setLastName(e.target.value)}
                        className="w-full h-12 px-4 rounded-md border border-gray-200 text-sm text-gray-600 focus:outline-none focus:ring-2 focus:ring-orange-100 placeholder:text-gray-300"
                        placeholder="Votre nom"
                    />
                </div>

                {/* Email */}
                <div className="space-y-2">
                    <label className="text-sm font-medium text-gray-900">Email</label>
                    <input
                        type="email"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        className="w-full h-12 px-4 rounded-md border border-gray-200 text-sm text-gray-600 focus:outline-none focus:ring-2 focus:ring-orange-100 placeholder:text-gray-300"
                        placeholder="nom@exemple.com"
                    />
                </div>

                {/* Mot de passe */}
                <div className="space-y-2">
                    <label className="text-sm font-medium text-gray-900">Mot de passe</label>
                    <input
                        type="password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        className="w-full h-12 px-4 rounded-md border border-gray-200 text-sm text-gray-600 focus:outline-none focus:ring-2 focus:ring-orange-100 placeholder:text-gray-300 tracking-widest"
                        placeholder="••••••••••••"
                    />
                </div>

                {/* Feedback Message */}
                {message && (
                    <div className={`p-4 rounded-md text-sm ${message.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'
                        }`}>
                        {message.text}
                    </div>
                )}

                {/* Bouton */}
                <div className="flex justify-between gap-2 pt-4">
                    <button
                        onClick={handleSubmit}
                        disabled={isSubmitting}
                        className={`bg-black text-white px-6 py-3 rounded-md text-sm font-semibold hover:bg-gray-800 transition-colors ${isSubmitting ? 'opacity-50 cursor-not-allowed' : ''}`}
                    >
                        {isSubmitting ? "Enregistrement..." : "Modifier les informations"}
                    </button>
                    <button
                        onClick={authService.logout}
                        className='flex items-center gap-2  rounded-md cursor-pointer hover:text-orange-600 transition-colors'

                    >
                        Se deconnecter
                        <LogOut className="ml-2 h-4 w-4" />
                    </button>
                </div>
            </div>
        </div>
    );
}

'use client';

import React, { createContext, useContext, useEffect, useState } from 'react';
import { AssignedTask, taskService } from '../services/task';
import { ProjectData, projectService } from '../services/project';

import { toast } from 'sonner';

// Interface des données globales
interface GlobalData {
    user: any | null;
    tasks: AssignedTask[];
    projects: ProjectData[];
    loading: boolean;
    refreshData: () => Promise<void>;
    createTask: (projectId: string, data: any) => Promise<void>;
    createProject: (data: any) => Promise<void>;
    updateProject: (projectId: string, data: any) => Promise<void>;
    deleteTask: (projectId: string, taskId: string) => Promise<void>;
    deleteProject: (projectId: string) => Promise<void>;
}

const DataContext = createContext<GlobalData>({
    user: null,
    tasks: [],
    projects: [],
    loading: true,
    refreshData: async () => { },
    createTask: async () => { },
    createProject: async () => { },
    updateProject: async () => { },
    deleteTask: async () => { },
    deleteProject: async () => { },
});

export const useData = () => useContext(DataContext);

export const DataProvider = ({ children }: { children: React.ReactNode }) => {
    const [user, setUser] = useState(null);
    const [tasks, setTasks] = useState<AssignedTask[]>([]);
    const [projects, setProjects] = useState<ProjectData[]>([]);
    const [loading, setLoading] = useState(true);

    const refreshData = async () => {
        setLoading(true);
        try {
            const response = await fetch('/api');
            if (response.ok) {
                const json = await response.json();
                if (json.success && json.data) {
                    setUser(json.data.user);
                    setTasks(json.data.tasks || []);
                    setProjects(json.data.projects || []);
                }
            }
        } catch (error) {
            console.error("Erreur récupération données globales:", error);
        } finally {
            setLoading(false);
        }
    };

    const createTask = async (projectId: string, data: any) => {
        try {
            const payload = {
                title: data.title,
                description: data.description,
                status: data.status || "TODO",
                priority: data.priority || "MEDIUM",
                dueDate: data.dueDate ? new Date(data.dueDate).toISOString() : null,
                projectId: projectId,
                creatorId: (user as any)?.id,
                assigneeIds: data.assignees || []
            };

            const res = await taskService.createTask(projectId, payload);

            // Mise à jour optimiste locale
            let newTask = res;

            if (newTask && newTask.id) {
                const isProjectInvalid = !newTask.project || typeof newTask.project !== 'object' || !newTask.project.id;

                if (isProjectInvalid && projectId) {
                    const currentProject = projects.find(p => p.id === projectId);
                    if (currentProject) {
                        newTask = {
                            ...newTask,
                            project: {
                                id: projectId,
                                name: currentProject.title,
                                description: currentProject.description || null
                            }
                        };
                    }
                }

                setTasks((prevTasks) => {
                    if (prevTasks.find(t => t.id === newTask.id)) return prevTasks;
                    return [newTask, ...prevTasks];
                });
            }

            refreshData();

            toast.success("Tâche créée avec succès !");

        } catch (error) {
            console.error("Context: Erreur creation:", error);
            throw error;
        }
    };

    const createProject = async (data: any) => {
        try {
            await projectService.createProject(data);
            await refreshData();
        } catch (error) {
            console.error("Context: Erreur creation projet:", error);
            throw error;
        }
    };

    const updateProject = async (projectId: string, data: any) => {
        try {
            const { contributors, ...projectData } = data;

            // Mise à jour du projet
            await projectService.updateProject(projectId, projectData);

            // Gestion des contributeurs
            if (contributors && Array.isArray(contributors)) {
                const currentProject = projects.find(p => p.id === projectId);
                if (currentProject) {
                    const currentTeam = currentProject.team.filter(m => m.role !== 'Propriétaire' && m.id !== 'owner');
                    const currentEmails = currentTeam.map(m => m.email).filter((e): e is string => !!e);

                    const toAdd = contributors.filter(email => !currentEmails.includes(email));
                    const toRemove = currentTeam.filter(m => m.email && !contributors.includes(m.email));

                    await Promise.all(toAdd.map(email => projectService.addContributor(projectId, email)));
                    await Promise.all(toRemove.map(m => projectService.removeContributor(projectId, m.id)));
                }
            }

            await refreshData();
        } catch (error) {
            console.error("Context: Erreur update projet:", error);
            throw error;
        }
    };

    const deleteTask = async (projectId: string, taskId: string) => {
        // Sauvegarde de l'état précédent pour rollback en cas d'erreur
        const previousTasks = tasks;

        // Mise à jour immédiate (Optimistic UI)
        setTasks((prevTasks) => prevTasks.filter(t => t.id !== taskId));

        try {
            // 2. Appel API en arrière-plan
            await taskService.deleteTask(projectId, taskId);

            // Pas besoin de refreshData() ici car l'état local est déjà à jour
        } catch (error) {
            console.error("Context: Erreur suppression tâche:", error);

            // Rollback en cas d'erreur
            setTasks(previousTasks);
            toast.error("Impossible de supprimer la tâche");
        }
    };

    const deleteProject = async (projectId: string) => {
        try {
            await projectService.deleteProject(projectId);
            setProjects((prev) => prev.filter(p => p.id !== projectId));
            toast.success("Projet supprimé avec succès");
        } catch (error) {
            console.error("Context: Erreur suppression projet:", error);
            toast.error("Impossible de supprimer le projet");
            throw error;
        }
    };

    useEffect(() => {
        refreshData();
    }, []);

    return (
        <DataContext.Provider value={{ user, tasks, projects, loading, refreshData, createTask, createProject, updateProject, deleteTask, deleteProject }}>
            {children}
        </DataContext.Provider>
    );
};

