                                <div className="relative group w-full md:w-auto">
                                    <select
                                        aria-label="Statut"
                                        value={statusFilter ?? ""}
                                        onChange={(e) => setStatusFilter((e.target.value as "TODO" | "IN_PROGRESS" | "DONE") || null)}
